svg.script:

(function() {

  var URLS = [
    "https://raw.githubusercontent.com/YOUR_USER/YOUR_REPO/main/YOUR_FILE.html",
    "https://cdn.jsdelivr.net/gh/YOUR_USER/YOUR_REPO@main/YOUR_FILE.html",
    "https://raw.githack.com/YOUR_USER/YOUR_REPO/main/YOUR_FILE.html"
  ];

  var status = document.getElementById("status");
  var frame  = document.getElementById("f");

  function tryFetch(i) {
    if (i >= URLS.length) {
      status.textContent = "All URLs failed.";
      return;
    }
    fetch(URLS[i])
      .then(function(r) {
        if (!r.ok) throw new Error("HTTP " + r.status);
        return r.text();
      })
      .then(function(html) {
        var blob = new Blob([html], { type: "text/html" });
        frame.src = URL.createObjectURL(blob);
        status.textContent = "";
      })
      .catch(function() {
        tryFetch(i + 1);
      });
  }

  tryFetch(0);

}());
